data_contract.type:
{
  "id": number,                                  // business_functions.id
  "name": string,                                // business_functions.name
  "inherited": boolean,                          // true se proviene da un antenato
  "source_category": { "id": number, "name": string } | null   // valorizzato SOLO se inherited=true
}

endpoint.response:
// ProductCategoryResource, campi ESISTENTI invariati + i due nuovi:
{
  "id": number, "name": string, "parent_id": number|null, "parent": {...}|null,
  "inherits_attributes": boolean, "description": string|null,
  "attributes": [...], "created_at": string,

  "business_function_id": number|null,                       // funzione PROPRIA (null se ereditata o assente)
  "business_function": { "id": number, "name": string } | null,   // funzione PROPRIA idratata
  "effective_business_function": EffectiveBusinessFunction | null // propria oppure ereditata
}
// NB: per invariante, se effective_business_function.inherited === true allora
//     business_function_id === null (e viceversa).

// Ogni nodo dell'albero: campi ESISTENTI invariati (id, name, parent_id, children[],
// attributes_count, products_count) + UNO nuovo:
{
  "business_function_id": number|null   // funzione PROPRIA del nodo (NON quella effettiva/ereditata)
}
// Il FE ricostruisce l'ereditarieta' risalendo `parent_id` sull'albero gia' in cache.
// Il backend resta l'unica autorita': il 422 di no-override e' comunque enforced.

// ProductResource, campi ESISTENTI invariati + uno nuovo, SOLA LETTURA:
{
  "id": number, "name": string, "description": ..., "cost": ..., "price": ...,
  "category_id": number|null, "category": {"id","name"}|null,
  "product_type": ..., "created_at": ...,

  "business_function": { "id": number, "name": string } | null  // effettiva della categoria; null se il prodotto non ha categoria
}
// Un `business_function_id` inviato in POST/PATCH /products viene IGNORATO (non fillable).

data_contract.tables:
// product-categories: nuova colonna `business_function` (type text, filterType `set`, derived).
//   Valore = nome della funzione EFFETTIVA (propria o ereditata).
// products: nuova colonna `business_function` (type text, filterType `set`, derived).
//   Valore = nome della funzione EFFETTIVA della categoria del prodotto.
// VINCOLO: filtro/sort server-side da ALLOW-LIST di colonne. Vietato passare input utente
//   a whereRaw/orderByRaw (backend.md §8). Se il sort su colonna derivata non e'
//   esprimibile in modo sicuro/efficiente, dichiararla non-sortable e riportarlo.
